import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

export type AnomalyRecord = {
  vendor: string;
  kind: "anomaly" | "renewal" | "duplicate";
  amount?: number;
  summary: string;
  flaggedAt: string;
};

const STORE_PATH = path.join(process.cwd(), "var", "spend.json");

export async function saveAnomaly(
  record: AnomalyRecord
): Promise<AnomalyRecord> {
  let all: AnomalyRecord[] = [];
  try {
    all = JSON.parse(await readFile(STORE_PATH, "utf-8")) as AnomalyRecord[];
  } catch {
    all = [];
  }
  all.push(record);
  await mkdir(path.dirname(STORE_PATH), { recursive: true });
  await writeFile(STORE_PATH, `${JSON.stringify(all, null, 2)}\n`, "utf-8");
  return record;
}

import { defineTool } from "eve/tools";
import { z } from "zod";

import { saveAnomaly } from "../lib/spend-store";

export default defineTool({
  description:
    "Flag a spend anomaly, upcoming renewal, or duplicate subscription for the owner digest.",
  inputSchema: z.object({
    vendor: z.string().min(1),
    kind: z.enum(["anomaly", "renewal", "duplicate"]),
    amount: z.number().optional(),
    summary: z.string().min(1),
  }),
  async execute(input) {
    const record = await saveAnomaly({
      ...input,
      flaggedAt: new Date().toISOString(),
    });
    return { saved: true, record };
  },
});

import { defineTool } from "eve/tools";
import { always } from "eve/tools/approval";
import { z } from "zod";

export default defineTool({
  description:
    "Propose cancelling or consolidating a subscription. Approval-gated; never executes the cancel itself.",
  inputSchema: z.object({
    vendor: z.string().min(1),
    rationale: z.string().min(1),
  }),
  approval: always(),
  async execute({ vendor, rationale }, ctx) {
    const sandbox = await ctx.getSandbox();
    const slug = vendor.toLowerCase().replaceAll(/[^a-z0-9]+/g, "-");
    const cancelPath = `cancellations/${slug}.md`;
    await sandbox.writeTextFile({ path: cancelPath, content: rationale });
    return { proposed: true, path: cancelPath };
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Proposing a cancellation parks on approval.",
  async test(t) {
    await t.send(
      "Propose cancelling duplicate Acme SaaS seat license immediately."
    );
    t.parked();
    t.calledTool("propose_cancel", { status: "pending", count: 1 });
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 2,
  timeoutMs: 180_000,
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Flagging a spend anomaly persists the finding.",
  async test(t) {
    await t.send("Flag Acme SaaS as a renewal for $1,200 due in 12 days.");
    t.succeeded();
    t.calledTool("flag_anomaly", {
      input: { vendor: /acme/i, kind: "renewal" },
    });
  },
});

